class TweetCounts {

    private Map<String, Map<Integer, Integer>> tweetCounts;

    public TweetCounts() {
        tweetCounts = new HashMap<>();
    }

    public void recordTweet(String tweetName, int time) {
        tweetCounts.computeIfAbsent(tweetName, k -> new HashMap<>()).put(time, tweetCounts.getOrDefault(tweetName, new HashMap<>()).getOrDefault(time, 0) + 1);
    }

    public List<Integer> getTweetCountsPerFrequency(String freq, String tweetName, int startTime, int endTime) {
        List<Integer> counts = new ArrayList<>();
        Map<Integer, Integer> tweetCountMap = tweetCounts.getOrDefault(tweetName, new HashMap<>());
        int chunkSize;
        if (freq.equals("minute")) {
            chunkSize = 60;
        } else if (freq.equals("hour")) {
            chunkSize = 3600;
        } else {
            chunkSize = 86400;
        }
        for (int i = startTime; i <= endTime; i += chunkSize) {
            int count = 0;
            for (int j = i; j < Math.min(i + chunkSize, endTime + 1); j++) {
                count += tweetCountMap.getOrDefault(j, 0);
            }
            counts.add(count);
        }
        return counts;
    }
}
